   ElfW(Addr) *const reloc_addr = reloc_addr_arg;
   const unsigned long int r_type = ELFW(R_TYPE) (reloc->r_info);

-# if !defined RTLD_BOOTSTRAP || !defined HAVE_Z_COMBRELOC
